class Admin_Model_Day extends Admin_Model_Base_Day
{

    public static function createDay($date = null) {
        if ($date === null) {
            $date = date("Y-m-d");
        }

        $day = new Admin_Model_Day();
        $day->Date = $date;
        $day->save();

        return $day;
    }

    public static function getDayByDate($date)
    {
        $day = Doctrine_Query::create()
            ->from('Admin_Model_Day d')
            ->where('d.Date = ?', $date)
            ->fetchOne(array(), Doctrine_Core::HYDRATE_ARRAY);

        return $day ?? null;
    }
}